diff --git a/dft/src/butterflies.rs b/dft/src/butterflies.rs
index 787d6b25..1b2df282 100644
--- a/dft/src/butterflies.rs
+++ b/dft/src/butterflies.rs
@@ -311,6 +311,36 @@ impl<F: Field> Butterfly<F> for ScaledDitButterfly<F> {
             self.apply_in_place(x_1, x_2);
         }
     }
+
+}
+
+impl<F: Field> ScaledDitButterfly<F> {
+    /// Like `apply_to_rows`, but takes a pre-broadcast `scale_packed` to avoid recomputing
+    /// `F::Packing::from(scale)` when the same scale is used across many blocks.
+    ///
+    /// Only `twiddle_times_scale` needs to be broadcast per call (since `twiddle` varies
+    /// per block), while `scale_packed` is already in packed form from a prior hoist.
+    #[inline]
+    pub fn apply_to_rows_with_packed_scale(
+        &self,
+        row_1: &mut [F],
+        row_2: &mut [F],
+        scale_packed: F::Packing,
+    ) {
+        let (shorts_1, suffix_1) = F::Packing::pack_slice_with_suffix_mut(row_1);
+        let (shorts_2, suffix_2) = F::Packing::pack_slice_with_suffix_mut(row_2);
+        // Only broadcast twiddle_times_scale here; scale_packed is already hoisted.
+        let twiddle_times_scale_packed = F::Packing::from(self.twiddle_times_scale);
+        for (x_1, x_2) in shorts_1.iter_mut().zip(shorts_2.iter_mut()) {
+            let x_1_scale = *x_1 * scale_packed;
+            let x_2_twiddle_scale = *x_2 * twiddle_times_scale_packed;
+            *x_1 = x_1_scale + x_2_twiddle_scale;
+            *x_2 = x_1_scale - x_2_twiddle_scale;
+        }
+        for (x_1, x_2) in suffix_1.iter_mut().zip(suffix_2.iter_mut()) {
+            self.apply_in_place(x_1, x_2);
+        }
+    }
 }

