@@ -332,4 +332,27 @@ impl<F: Field> Butterfly<F> for TwiddleFreeButterfly {
     fn apply<PF: PackedField<Scalar = F>>(&self, x_1: PF, x_2: PF) -> (PF, PF) {
         (x_1 + x_2, x_1 - x_2)
     }
+
+    /// Override `apply_to_rows` to avoid the tuple temporary from `apply_in_place`.
+    ///
+    /// The default path goes through `apply_in_place` → `(*x_1, *x_2) = self.apply(...)`,
+    /// which may create tuple temporaries. A direct override computing sum/diff inline avoids
+    /// any intermediate allocation and allows LLVM to keep results in registers.
+    #[inline]
+    fn apply_to_rows(&self, row_1: &mut [F], row_2: &mut [F]) {
+        let (shorts_1, suffix_1) = F::Packing::pack_slice_with_suffix_mut(row_1);
+        let (shorts_2, suffix_2) = F::Packing::pack_slice_with_suffix_mut(row_2);
+        for (x_1, x_2) in shorts_1.iter_mut().zip(shorts_2.iter_mut()) {
+            let sum = *x_1 + *x_2;
+            let diff = *x_1 - *x_2;
+            *x_1 = sum;
+            *x_2 = diff;
+        }
+        for (x_1, x_2) in suffix_1.iter_mut().zip(suffix_2.iter_mut()) {
+            let sum = *x_1 + *x_2;
+            let diff = *x_1 - *x_2;
+            *x_1 = sum;
+            *x_2 = diff;
+        }
+    }
 }

